payloadFactory.format:
{
"endorsementStatusCode": "$1",
"processingStatus": "NO_ACTION_REQUIRED",
"message": "Endorsement has already been validated, no further validation is required."
}

else.script:
var root = mc.getPayloadJSON();

// Validate structure
if (!root || !root.data || root.data.length === 0) {
    throw "Invalid DB response structure";
}

var payload = root.data[0];

function num(v){
    return (v !== null && v !== undefined) ? Number(v) : 0;
}

// =============================
// Rates & constants
// =============================
var vehicleRate        = 0.025;
var ownDamageRate      = 0.012;
var accidentRate       = 0.05;
var violationRate      = 0.03;
var highMileageRate    = 0.05;
var mileageLimit       = 12000;
var prorata            = 0.75;
var fee                = 500;
var minDriverSurcharge = 1000;

var addedVehiclePremium = 0;
var updatedVehiclePremium = 0;
var addedCoveragePremium = 0;

// =============================
// Added Vehicles
// =============================
var addedVehicles =
    (payload.changes &&
     payload.changes.insurableObjects &&
     payload.changes.insurableObjects.added) || [];

addedVehicles.forEach(function(v){

    var value = num(v.vehicle && v.vehicle.vehicleValue);

    addedVehiclePremium += value * vehicleRate;
    addedVehiclePremium += value * ownDamageRate;

    if(num(v.vehicle && v.vehicle.annualMileage) > mileageLimit){
        addedVehiclePremium += value * highMileageRate;
    }
});

// =============================
// Updated Vehicles
// =============================
var updatedVehicles =
    (payload.changes &&
     payload.changes.insurableObjects &&
     payload.changes.insurableObjects.updated) || [];

updatedVehicles.forEach(function(v){

    if(v.fieldValues && v.fieldValues.vehicle){

        var value = num(v.fieldValues.vehicle.vehicleValue);

        updatedVehiclePremium += value * vehicleRate;

        if(num(v.fieldValues.vehicle.annualMileage) > mileageLimit){
            updatedVehiclePremium += value * highMileageRate;
        }
    }

    if(v.fieldValues &&
       v.fieldValues.coverages &&
       v.fieldValues.coverages.added){

        v.fieldValues.coverages.added.forEach(function(){
            addedCoveragePremium += 500000 * ownDamageRate;
        });
    }

});

var basePremium =
    addedVehiclePremium +
    updatedVehiclePremium +
    addedCoveragePremium;

// =============================
// Risky Drivers 
// =============================
var riskyDrivers = 0;

var driversAdded =
    (payload.changes &&
     payload.changes.drivers &&
     payload.changes.drivers.added) || [];

var driversUpdated =
    (payload.changes &&
     payload.changes.drivers &&
     payload.changes.drivers.updated) || [];

// Added drivers also trigger surcharge
driversAdded.forEach(function(d){

    var accident = num(d.accidentCount);
    var violation = num(d.violationCount);

    if(accident > 0 || violation > 0){
        riskyDrivers++;
    }
    else{
        riskyDrivers++;
    }
});


driversUpdated.forEach(function(d){

    var accident = num(d.fieldValues && d.fieldValues.accidentCount);
    var violation = num(d.fieldValues && d.fieldValues.violationCount);

    if(accident > 0 || violation > 0){
        riskyDrivers++;
    }
    else if(d.fieldValues){
        riskyDrivers++;
    }
});

// =============================
// Driver Load
// =============================
var driverLoad = 0;

if(riskyDrivers > 0){
    if(basePremium > 0){
        driverLoad =
            basePremium *
            (riskyDrivers * (accidentRate + violationRate));
    } else {
        driverLoad =
            riskyDrivers * minDriverSurcharge;
    }
}

var totalPremium =
    (basePremium + driverLoad) * prorata;

var pricing = {
    totalPremium: totalPremium,
    grossFees: fee,
    amounts: [
        {
            amountTypeCode: "PREMIUM",
            amountValue: Number(totalPremium.toFixed(2)),
            currencyCode: "USD"
        },
        {
            amountTypeCode: "FEE",
            amountValue: Number(fee.toFixed(2)),
            currencyCode: "USD"
        }
    ]
};

// Store for update call
mc.setProperty("calculatedPricing", JSON.stringify(pricing));
